        "testable_assertion": "No API call, database mutation, or admin action can set transactional email preferences to disabled. Any attempt must be rejected."
      },
      {
        "rule": "Marketing emails are opt-out-able by the user",
        "testable_assertion": "A user can set marketing_emails_enabled to false, and the system persists and respects that preference."
      }
    ],
    "architecture_guidance": [
      {
        "decision": "PATCH /users/{id}/notification-preferences is the single endpoint for preference changes",
        "implementation_note": "Accept a JSON body with marketing_emails_enabled (boolean). The field transactional_emails_enabled may appear in the request but must be rejected if set to false."
      },
      {
        "decision": "Store marketing email preference as a boolean field: marketing_emails_enabled",
        "implementation_note": "Default should be true (opted in). Transactional emails have no user-facing toggle — they are always enabled."
      },
