        "then": "The preference is persisted, response is 200, and marketing emails are no longer sent to the user"
      },
      {
        "criterion": "User can opt back in to marketing emails",
        "given": "A user who previously opted out of marketing emails",
        "when": "They send PATCH /users/{id}/notification-preferences with {\"marketing_emails_enabled\": true}",
        "then": "The preference is persisted, response is 200, and marketing emails resume"
      },
